var minOperations = function(nums, k) {
    let combined = 0;
    for (const x of nums) combined ^= x;
    let diff = combined ^ k;
    let count = 0;
    while (diff !== 0) {
        count += diff & 1;
        diff >>>= 1;
    }
    return count;
};
